#!/usr/bin/env node
// @author kongweiguang

import { execFileSync } from "node:child_process";
import { existsSync, mkdirSync, readFileSync, readdirSync, statSync, writeFileSync } from "node:fs";
import { platform } from "node:os";
import path from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const args = parseArgs(process.argv.slice(2));
const dateStamp = new Date().toISOString().slice(0, 10).replaceAll("-", "");
const outputPath = path.resolve(
  repoRoot,
  args.output ?? `.updeng/docs/verification/performance-baseline-${dateStamp}.json`,
);
const verificationDir = path.join(repoRoot, ".updeng", "docs", "verification");

const report = {
  schemaVersion: 1,
  generatedAt: new Date().toISOString(),
  git: readGitMetadata(),
  environment: {
    node: process.version,
    platform: platform(),
  },
  reports: {
    directoryList: readReport("perf-directory-list-baseline.json"),
    frontendBundle: readReport("frontend-bundle-baseline.json"),
    terminalOutput: readReport("terminal-output-baseline.json"),
  },
  rustTimings: latestCargoTimingReport(),
};

report.summary = {
  directoryListPass: report.reports.directoryList?.summary?.pass ?? null,
  frontendAssetCount: report.reports.frontendBundle?.assetCount ?? null,
  frontendRawBytes: report.reports.frontendBundle?.totals?.bytes ?? null,
  latestCargoTimingReport: report.rustTimings?.path ?? null,
  pass:
    report.reports.directoryList?.summary?.pass === true &&
    report.reports.terminalOutput?.summary?.pass === true &&
    Boolean(report.reports.frontendBundle),
  terminalOutputPass: report.reports.terminalOutput?.summary?.pass ?? null,
};

mkdirSync(path.dirname(outputPath), { recursive: true });
writeFileSync(outputPath, `${JSON.stringify(report, null, 2)}\n`, "utf8");

console.log(`Performance baseline summary: ${report.summary.pass ? "pass" : "incomplete"}.`);
console.log(`Report: ${path.relative(repoRoot, outputPath).replaceAll("\\", "/")}`);

if (!report.summary.pass) {
  process.exitCode = 1;
}

function readReport(fileName) {
  const filePath = path.join(verificationDir, fileName);
  if (!existsSync(filePath)) {
    return null;
  }
  return JSON.parse(readFileSync(filePath, "utf8"));
}

function latestCargoTimingReport() {
  const timingDir = path.join(repoRoot, "src-tauri", "target", "cargo-timings");
  if (!existsSync(timingDir)) {
    return null;
  }
  const latest = readdirSync(timingDir)
    .filter((fileName) => fileName.endsWith(".html") && fileName !== "cargo-timing.html")
    .map((fileName) => {
      const filePath = path.join(timingDir, fileName);
      return {
        fileName,
        filePath,
        stat: statSync(filePath),
      };
    })
    .sort((left, right) => right.stat.mtimeMs - left.stat.mtimeMs)[0];
  if (!latest) {
    return null;
  }
  return {
    generatedAt: latest.stat.mtime.toISOString(),
    path: path.relative(repoRoot, latest.filePath).replaceAll("\\", "/"),
    sizeBytes: latest.stat.size,
  };
}

function parseArgs(rawArgs) {
  const parsed = {};
  for (let index = 0; index < rawArgs.length; index += 1) {
    const arg = rawArgs[index];
    if (!arg.startsWith("--")) {
      continue;
    }
    const key = arg.slice(2);
    const value = rawArgs[index + 1];
    if (!value || value.startsWith("--")) {
      parsed[key] = true;
      continue;
    }
    parsed[key] = value;
    index += 1;
  }
  return parsed;
}

function readGitMetadata() {
  return {
    branch: runGit(["rev-parse", "--abbrev-ref", "HEAD"]),
    commit: runGit(["rev-parse", "--short", "HEAD"]),
    dirty: runGit(["status", "--short"]) !== "",
  };
}

function runGit(argsForGit) {
  try {
    return execFileSync("git", argsForGit, {
      cwd: repoRoot,
      encoding: "utf8",
      stdio: ["ignore", "pipe", "ignore"],
    }).trim();
  } catch {
    return null;
  }
}

//! Agent session Tauri Commands。
//!
//! @author kongweiguang

use serde::{Deserialize, Serialize};
use std::time::{SystemTime, UNIX_EPOCH};
use tauri::State;

use crate::{
    error::{AppError, AppResult},
    models::agent_session::{
        AgentId, AgentProviderSession, AgentSessionCreateRequest, AgentSessionId,
        AgentSessionLaunchRequest, AgentSessionList, AgentSessionRecord, AgentSessionTarget,
        AgentSessionUpdateRequest, AgentTargetLiveStatus, AgentTerminalSnapshotContext,
        AGENT_SESSION_SCHEMA_VERSION,
    },
    security::redaction::redact_terminal_text,
    services::{
        agent_target_hydration_service::hydrate_agent_target_binding,
        terminal_session_binding_service::{
            AgentTargetBindingRequest, AgentTargetBindingSnapshot,
            AgentTargetBindingStatus as RuntimeAgentTargetBindingStatus,
        },
    },
    state::AppState,
};

const AGENT_SESSION_TERMINAL_SNAPSHOT_BYTES: usize = 24 * 1024;

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct AgentSessionCreateCommandRequest {
    pub agent_id: AgentId,
    #[serde(default)]
    pub title: Option<String>,
    #[serde(default)]
    pub launch: Option<AgentSessionLaunchRequest>,
    #[serde(default)]
    pub target: Option<AgentSessionTargetCommandRequest>,
    #[serde(default)]
    pub provider: Option<AgentProviderSession>,
    #[serde(default)]
    pub mcp_endpoint: Option<String>,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct AgentSessionTargetCommandRequest {
    #[serde(default)]
    pub binding_id: Option<String>,
    #[serde(default)]
    pub binding_generation: u64,
    #[serde(default)]
    pub pane_id: Option<String>,
    #[serde(default)]
    pub tab_id: Option<String>,
    #[serde(default)]
    pub target_terminal_session_id: Option<String>,
    #[serde(default)]
    pub target_ref: Option<String>,
    #[serde(default)]
    pub target_kind: Option<String>,
    #[serde(default)]
    pub cwd: Option<String>,
    #[serde(default)]
    pub shell: Option<String>,
    #[serde(default)]
    pub live_status: Option<AgentTargetLiveStatus>,
    #[serde(default)]
    pub last_seen_at: Option<String>,
}

#[tauri::command]
pub fn agent_session_create(
    state: State<'_, AppState>,
    request: AgentSessionCreateCommandRequest,
) -> Result<AgentSessionRecord, String> {
    create_agent_session(&state, request).map_err(|error| error.to_string())
}

#[tauri::command]
pub fn agent_session_list(state: State<'_, AppState>) -> Result<AgentSessionList, String> {
    list_agent_sessions(&state).map_err(|error| error.to_string())
}

fn list_agent_sessions(state: &AppState) -> AppResult<AgentSessionList> {
    let listed = state.agent_sessions().list_sessions()?;
    let live_ids = live_terminal_session_ids(state)?;
    let sessions = listed
        .sessions
        .into_iter()
        .map(|record| {
            hydrate_agent_target_binding(
                state.agent_sessions(),
                state.terminal_session_bindings(),
                &record.session.agent_session_id,
                live_ids.iter().map(String::as_str),
            )
            .unwrap_or(record)
        })
        .collect();
    Ok(AgentSessionList {
        sessions,
        diagnostics: listed.diagnostics,
    })
}

fn get_agent_session(
    state: &AppState,
    agent_session_id: &AgentSessionId,
) -> AppResult<AgentSessionRecord> {
    let live_ids = live_terminal_session_ids(state)?;
    hydrate_agent_target_binding(
        state.agent_sessions(),
        state.terminal_session_bindings(),
        agent_session_id,
        live_ids.iter().map(String::as_str),
    )
}

fn live_terminal_session_ids(state: &AppState) -> AppResult<Vec<String>> {
    Ok(state
        .terminals()
        .list_sessions()?
        .into_iter()
        .map(|session| session.id)
        .collect())
}

