        None,
        &request(PortForwardKind::Local),
    )
    .expect("build plan");

    assert_eq!(plan.executable, "ssh");
    assert!(plan.args.windows(2).any(|pair| pair == ["-p", "2222"]));
    assert!(plan
        .args
        .windows(2)
        .any(|pair| pair == ["-L", "127.0.0.1:15432:127.0.0.1:5432"]));
    assert!(plan
        .args
